    ('NUMBER', r'\b\d+(\.\d+)?\b'), # Integers and floats
    ('ID',     r'[a-zA-Z_][a-zA-Z0-9_]*'),  # Identifiers (variables, functions)
    ('OP',     r'==|!=|<=|>=|\+|\-|\*|\/|\*\*|%|<|>'), # Operators
    ('LPAREN', r'\('),
    ('RPAREN', r'\)'),
    ('COMMA',  r','),
    ('SKIP',   r'[ \\t]+'), # Skips whitespace
    ('MISMATCH',r'.'),      # Any other character
]

TOKEN_REGEX = '|'.join([f'(?P<{name}>{pattern})' for name, pattern in TOKEN_SPECIFICATION if name != 'SKIP'])

class Token:
    def __init__(self, type, value):
        self.type = type
        self.value = value

    def __repr__(self):
        return f"Token({self.type}, {repr(self.value)})"


def tokenize(source_string):
    tokens = []
    for mo in re.finditer(TOKEN_REGEX, source_string):
        kind = mo.lastgroup
        value = mo.group(0)
