    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0
        self.current_token = None
        if self.tokens:
            self.advance()

    def advance(self):
        if self.pos < len(self.tokens) - 1:
            self.pos += 1
            self.current_token = self.tokens[self.pos]
        else:
            self.current_token = None # End of input

